import { useState, useEffect } from 'react'
import { Tree, Spin, Empty, message } from 'antd'
import { FileOutlined, FolderOutlined } from '@ant-design/icons'
import type { DataNode } from 'antd/es/tree'

// 浏览器环境下替代 path.join 的工具函数
const pathJoin = (...parts: string[]): string => {
  return parts.filter(Boolean).join('/')
}

interface OutlineTreeProps {
  projectRoot: string
  activeChapter: string | null
  onSelect: (filePath: string) => void
}

interface FileEntry {
  name: string
  isDirectory: boolean
  isFile: boolean
  path: string
  children?: FileEntry[]
}

const OutlineTree = ({ projectRoot, activeChapter, onSelect }: OutlineTreeProps) => {
  const [treeData, setTreeData] = useState<DataNode[]>([])
  const [loading, setLoading] = useState(false)
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([])

  // 读取目录结构
  const loadDirectory = async (dirPath: string): Promise<FileEntry[]> => {
    try {
      const entries = await window.electronAPI.readdir(dirPath)
      if (!Array.isArray(entries)) return []

      const result: FileEntry[] = []

      for (const entry of entries) {
        const fullPath = pathJoin(dirPath, entry.name)

        if (entry.isDirectory) {
          const children = await loadDirectory(fullPath)
          result.push({
            name: entry.name,
            isDirectory: true,
            isFile: false,
            path: fullPath,
            children
          })
        } else if (entry.isFile && entry.name.endsWith('.md')) {
          result.push({
            name: entry.name.replace('.md', ''),
            isDirectory: false,
            isFile: true,
            path: fullPath
          })
        }
      }

      return result.sort((a, b) => {
        if (a.isDirectory && !b.isDirectory) return -1
        if (!a.isDirectory && b.isDirectory) return 1
        return a.name.localeCompare(b.name)
      })
    } catch (error) {
      console.error('读取目录失败:', error)
      return []
    }
  }

  // 转换为 Ant Design Tree 需要的格式
  const convertToTreeData = (entries: FileEntry[], parentKey: string = ''): DataNode[] => {
    return entries.map((entry, index) => {
      const key = parentKey ? `${parentKey}-${index}` : `${index}`

      if (entry.isDirectory && entry.children) {
        return {
          title: entry.name,
          key,
          icon: <FolderOutlined />,
          children: convertToTreeData(entry.children, key),
          isLeaf: false
        }
      } else {
        return {
          title: entry.name,
          key: entry.path,
          icon: <FileOutlined />,
          isLeaf: true
        }
      }
    })
  }

  // 加载大纲
  useEffect(() => {
    const loadOutline = async () => {
      if (!projectRoot) return

      setLoading(true)
      try {
        const plotsDir = pathJoin(projectRoot, 'plots')
        const existsResult = await window.electronAPI.exists(plotsDir)
        if (!existsResult || !existsResult.success || !existsResult.exists) {
          await window.electronAPI.mkdir(plotsDir)
          setTreeData([])
          return
        }

        const entries = await loadDirectory(plotsDir)
        const data = convertToTreeData(entries)
        setTreeData(data)

        const getAllKeys = (nodes: DataNode[]): string[] => {
          let keys: string[] = []
          nodes.forEach(node => {
            keys.push(node.key as string)
            if (node.children) keys = keys.concat(getAllKeys(node.children))
          })
          return keys
        }
        setExpandedKeys(getAllKeys(data))
      } catch (error) {
        message.error('加载大纲失败')
        console.error(error)
      } finally {
        setLoading(false)
      }
    }

    loadOutline()
  }, [projectRoot])

  // 监听文件变化，自动刷新大纲
  useEffect(() => {
    if (!projectRoot) return

    const plotsDir = pathJoin(projectRoot, 'plots')
    window.electronAPI.fsWatch(plotsDir)

    const removeListener = window.electronAPI.onFsChange(() => {
      loadDirectory(pathJoin(projectRoot, 'plots')).then(entries => {
        const data = convertToTreeData(entries)
        setTreeData(data)
      })
    })

    return () => {
      removeListener()
      window.electronAPI.fsUnwatch()
    }
  }, [projectRoot])

  // 处理选择
  const handleSelect = (selectedKeys: React.Key[]) => {
    if (selectedKeys.length === 0) return
    const key = String(selectedKeys[0])
    if (key.startsWith('/') || key.includes('.md')) {
      onSelect(key)
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        <Spin tip="加载中..." />
      </div>
    )
  }

  if (treeData.length === 0) {
    return (
      <div style={{ padding: 20 }}>
        <Empty
          description="暂无章节"
          image={Empty.PRESENTED_IMAGE_SIMPLE}
        />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', overflow: 'auto', padding: 10 }}>
      <Tree
        treeData={treeData}
        expandedKeys={expandedKeys}
        selectedKeys={activeChapter ? [activeChapter] : []}
        onSelect={handleSelect}
        onExpand={setExpandedKeys}
        showIcon
        defaultExpandAll
      />
    </div>
  )
}

export default OutlineTree

/**
 * 人物关系图可视化
 * 使用 graphology 实现力导向图
 * 节点：人物，边：人物关系
 * 支持点击查看详情
 */

import { useEffect, useRef, useState, useCallback } from 'react'
import { Card, Button, Space, message, Spin, Drawer, Descriptions, Tag } from 'antd'
import { ReloadOutlined } from '@ant-design/icons'
import Graph from 'graphology'
import forceAtlas2 from 'graphology-layout-forceatlas2'

interface GraphNode {
  id: string
  label: string
  mbti?: string
  type?: string
}

interface RawRelationship {
  from: string
  to: string
  type: string
  strength: number
  development?: unknown[]
}

interface GraphEdge {
  id: string
  source: string
  target: string
  label: string
  weight: number
  from: string
  to: string
  type: string
  strength: number
}

interface CharacterGraphProps {
  projectRoot: string | null
  onNodeClick?: (characterName: string) => void
}

const REL_TYPE_COLORS: Record<string, string> = {
  mentor: '#1677ff',
  rival: '#ff4d4f',
  love: '#eb2f96',
  family: '#52c41a',
  friend: '#13c2c2',
  master: '#722ed1',
  enemy: '#d4380d',
}

const CharacterGraph: React.FC<CharacterGraphProps> = ({ projectRoot }) => {
  const [loading, setLoading] = useState(false)
  const [graphData, setGraphData] = useState<{
    nodes: GraphNode[]
    edges: GraphEdge[]
  } | null>(null)
  const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null)
  const [drawerVisible, setDrawerVisible] = useState(false)

  const loadGraphData = useCallback(async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      // 读取 relationships.yaml
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      const relData = relResult.success
        ? (relResult.data as Record<string, unknown>)
        : { relationships: [] }
      const rels = (relData.relationships as RawRelationship[]) || []

      // 读取角色基本信息
      const charsDir = `${projectRoot}/characters`
      const charFilesResult = await window.electronAPI.readdir(charsDir)
      if (!charFilesResult.success) { console.error('读取characters目录失败:', charFilesResult.error); }
      const charFiles = charFilesResult.data || []
      const charInfoMap: Record<string, GraphNode> = {}

      for (const file of charFiles) {
        if (file.isFile && file.name.endsWith('.yaml')) {
          const charResult = await window.electronAPI.yaml.read(`${charsDir}/${file.name}`)
          if (charResult.success && charResult.data) {
            const data = charResult.data as Record<string, unknown>
            const name = String(data.name || file.name.replace('.yaml', ''))
            charInfoMap[name] = {
              id: name,
              label: name,
              mbti: data.mbti as string | undefined,
              type: 'character',
            }
          }
        }
      }

      // 构建节点（所有出现在关系中的角色）
      const nodeSet = new Set<string>()
      for (const rel of rels) {
        nodeSet.add(rel.from)
        nodeSet.add(rel.to)
      }

      const nodes: GraphNode[] = Array.from(nodeSet).map(name => {
        const info = charInfoMap[name] || {}
        return {
          id: name,
          label: name,
          mbti: info.mbti,
          type: info.type,
        }
      })

      const edges: GraphEdge[] = rels.map((rel: RawRelationship, idx: number) => ({
        id: `edge-${idx}`,
        source: String(rel.from || ''),
        target: String(rel.to || ''),
        from: String(rel.from || ''),
        to: String(rel.to || ''),
        label: String(rel.type || ''),
        type: String(rel.type || ''),
        weight: (rel.strength as number) || 0.5,
        strength: (rel.strength as number) || 0.5,
      }))

      setGraphData({ nodes, edges })
    } catch (error) {
      console.error('加载关系图失败:', error)
      message.error('加载关系图失败')
    } finally {
      setLoading(false)
    }
  }, [projectRoot])

  useEffect(() => {
    loadGraphData()
  }, [loadGraphData])

  const handleNodeClick = useCallback((nodeId: string) => {
    setSelectedNode(prev => graphData?.nodes.find(n => n.id === nodeId) || prev)
    setDrawerVisible(true)
  }, [graphData])

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  if (loading) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Spin tip="加载关系图..." />
      </div>
    )
  }

  if (!graphData || graphData.nodes.length === 0) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <div style={{ color: '#999', marginBottom: 16 }}>
          暂无人物关系数据
        </div>
        <Button icon={<ReloadOutlined />} onClick={loadGraphData}>
          刷新
        </Button>
      </div>
    )
  }

  // 简单的 SVG 力导向图实现
  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div
        style={{
          padding: '8px 16px',
          borderBottom: '1px solid #e8e8e8',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <span style={{ fontSize: 13 }}>
          人物关系图 · {graphData.nodes.length} 人 / {graphData.edges.length} 条关系
        </span>
        <Space>
          <Button size="small" icon={<ReloadOutlined />} onClick={loadGraphData}>
            刷新
          </Button>
        </Space>
      </div>

      <ForceGraph
        nodes={graphData.nodes}
        edges={graphData.edges}
        onNodeClick={handleNodeClick}
      />

      <Drawer
        title={selectedNode?.label}
        open={drawerVisible}
        onClose={() => setDrawerVisible(false)}
        width={300}
      >
        {selectedNode && (
          <Descriptions column={1} size="small">
            <Descriptions.Item label="名称">{selectedNode.label}</Descriptions.Item>
            {selectedNode.mbti && (
              <Descriptions.Item label="MBTI">
                <Tag color="purple">{selectedNode.mbti}</Tag>
              </Descriptions.Item>
            )}
            <Descriptions.Item label="相关关系">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {graphData?.edges
                  .filter(e => e.source === selectedNode.id || e.target === selectedNode.id)
                  .map((edge, idx) => {
                    const other = edge.source === selectedNode.id ? edge.target : edge.source
                    return (
                      <Tag
                        key={idx}
                        color={REL_TYPE_COLORS[edge.label] || 'default'}
                      >
                        {other} ({edge.label})
                      </Tag>
                    )
                  })}
              </div>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Drawer>
    </div>
  )
}

// 简单的 SVG 力导向图组件
interface ForceGraphProps {
  nodes: GraphNode[]
  edges: GraphEdge[]
  onNodeClick: (nodeId: string) => void
}

const ForceGraph: React.FC<ForceGraphProps> = ({ nodes, edges, onNodeClick }) => {
  const containerRef = useRef<HTMLDivElement>(null)
  const [positions, setPositions] = useState<Record<string, { x: number; y: number }>>({})
  const [dragging, setDragging] = useState<string | null>(null)

  // 初始化力导向布局
  useEffect(() => {
    if (nodes.length === 0) return

    const graph = new Graph()

    // 添加节点
    for (const node of nodes) {
      graph.addNode(node.id, {
        label: node.label,
        x: Math.random() * 400 + 100,
        y: Math.random() * 300 + 100,
        size: 20,
        color: '#1890ff',
      })
    }

    // 添加边
    for (const edge of edges) {
      if (graph.hasNode(edge.source) && graph.hasNode(edge.target)) {
        try {
          graph.addEdge(edge.source, edge.target, {
            label: edge.label,
            size: edge.weight * 3 + 1,
            color: REL_TYPE_COLORS[edge.label] || '#999',
          })
        } catch {
          // 边已存在则跳过
        }
      }
    }

    // 运行 ForceAtlas2
    if (graph.order > 0) {
      try {
        forceAtlas2.assign(graph, {
          iterations: 100,
          settings: {
            gravity: 1,
            scalingRatio: 10,
            strongGravityMode: true,
          },
        })
      } catch (e) {
        console.warn('ForceAtlas2 布局失败，使用随机位置:', e)
      }
    }

    // 提取位置
    const pos: Record<string, { x: number; y: number }> = {}
    graph.forEachNode((nodeId, attrs) => {
      pos[nodeId] = { x: (attrs.x as number) || 0, y: (attrs.y as number) || 0 }
    })

    setPositions(pos)
  }, [nodes, edges])

  if (nodes.length === 0) return null

  // 计算 bounds
  const posValues = Object.values(positions)
  if (posValues.length === 0) return null

  const minX = Math.min(...posValues.map(p => p.x))
  const maxX = Math.max(...posValues.map(p => p.x))
  const minY = Math.min(...posValues.map(p => p.y))
  const maxY = Math.max(...posValues.map(p => p.y))
  const rangeX = maxX - minX || 1
  const rangeY = maxY - minY || 1

  const width = 500
  const height = 400
  const padding = 40
  const scaleX = (width - 2 * padding) / rangeX
  const scaleY = (height - 2 * padding) / rangeY

  const getX = (x: number) => (x - minX) * scaleX + padding
  const getY = (y: number) => (y - minY) * scaleY + padding

  return (
    <div
      ref={containerRef}
      style={{ flex: 1, overflow: 'auto', background: '#fafafa' }}
    >
      <svg width={width} height={height} style={{ cursor: 'grab' }}>
        {/* 绘制边 */}
        {edges.map(edge => {
          const fromPos = positions[edge.source]
          const toPos = positions[edge.target]
          if (!fromPos || !toPos) return null

          const x1 = getX(fromPos.x)
          const y1 = getY(fromPos.y)
          const x2 = getX(toPos.x)
          const y2 = getY(toPos.y)

          // 计算边的中点（用于放置标签）
          const midX = (x1 + x2) / 2
          const midY = (y1 + y2) / 2

          return (
            <g key={edge.id}>
              <line
                x1={x1}
                y1={y1}
                x2={x2}
                y2={y2}
                stroke={REL_TYPE_COLORS[edge.label] || '#999'}
                strokeWidth={Math.max(edge.weight * 3 + 1, 1)}
                strokeOpacity={0.6}
              />
              <text
                x={midX}
                y={midY - 5}
                textAnchor="middle"
                fontSize={10}
                fill={REL_TYPE_COLORS[edge.label] || '#999'}
                style={{ pointerEvents: 'none' }}
              >
                {edge.label}
              </text>
            </g>
          )
        })}

        {/* 绘制节点 */}
        {nodes.map(node => {
          const pos = positions[node.id]
          if (!pos) return null

          const cx = getX(pos.x)
          const cy = getY(pos.y)

          return (
            <g
              key={node.id}
              style={{ cursor: 'pointer' }}
              onClick={() => onNodeClick(node.id)}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="#1890ff"
                stroke="#fff"
                strokeWidth={2}
              />
              <text
                x={cx}
                y={cy + 4}
                textAnchor="middle"
                fontSize={11}
                fill="#fff"
                style={{ pointerEvents: 'none', fontWeight: 'bold' }}
              >
                {node.label.slice(0, 2)}
              </text>
              <text
                x={cx}
                y={cy - 22}
                textAnchor="middle"
                fontSize={11}
                fill="#333"
                style={{ pointerEvents: 'none' }}
              >
                {node.label}
              </text>
            </g>
          )
        })}
      </svg>

      {/* 图例 */}
      <div
        style={{
          padding: '8px 16px',
          fontSize: 11,
          color: '#666',
          borderTop: '1px solid #e8e8e8',
          display: 'flex',
          gap: 12,
          flexWrap: 'wrap',
        }}
      >
        {Object.entries(REL_TYPE_COLORS).map(([type, color]) => (
          <span key={type} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <span
              style={{
                display: 'inline-block',
                width: 16,
                height: 2,
                background: color,
              }}
            />
            {type}
          </span>
        ))}
      </div>
    </div>
  )
}

export default CharacterGraph

import { useState, useEffect, useRef, useCallback } from 'react'
import { Layout, Menu, Button, message } from 'antd'
import {
  SaveOutlined,
  FolderOpenOutlined,
  BookOutlined,
  UserOutlined,
  SettingOutlined,
  ThunderboltOutlined,
  SearchOutlined,
} from '@ant-design/icons'
import OutlineTree from './OutlineTree'
import factsStore from '../db'
import Editor, { EditorHandle } from './Editor'
import FactsPanel from './FactsPanel'
import AIToolsPanel from './AIToolsPanel'
import CharactersPage from '../pages/CharactersPage'
import SettingsPage from '../pages/SettingsPage'
import AppSettingsPage from '../pages/AppSettingsPage'
import ProjectManager from './ProjectManager'
import VectorSearchPanel from './VectorSearchPanel'
import AnalysisPanel from './AnalysisPanel'
import ExportManager from './ExportManager'
import type { MenuProps } from 'antd'

const { Sider, Content } = Layout

type TabKey = 'outline' | 'characters' | 'world' | 'facts' | 'search' | 'appSettings'
type RightPanelTab = 'ai' | 'analysis'

// 左侧菜单
const siderMenuItems: MenuProps['items'] = [
  { key: 'outline', icon: <BookOutlined />, label: '大纲导航' },
  { key: 'characters', icon: <UserOutlined />, label: '角色管理' },
  { key: 'world', icon: <SettingOutlined />, label: '世界设定' },
  { key: 'facts', icon: <ThunderboltOutlined />, label: '事实台账' },
  { key: 'search', icon: <SearchOutlined />, label: '语义检索' },
  { key: 'appSettings', icon: <SettingOutlined />, label: '应用设置' },
]

const Workbench = () => {
  const [activeTab, setActiveTab] = useState<TabKey>('outline')
  const [rightPanelTab, setRightPanelTab] = useState<RightPanelTab>('ai')
  const [activeChapter, setActiveChapter] = useState<string | null>(null)
  const [chapterContent, setChapterContent] = useState('')
  const [projectRoot, setProjectRoot] = useState<string | null>(null)
  const [projectName, setProjectName] = useState<string>('小说')
  const [isDirty, setIsDirty] = useState(false)
  const autoSaveTimerRef = useRef<NodeJS.Timeout | null>(null)
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle')
  const [projectManagerVisible, setProjectManagerVisible] = useState(false)
  const [exportManagerVisible, setExportManagerVisible] = useState(false)
  const editorRef = useRef<EditorHandle>(null)

  // 初始化项目
  useEffect(() => {
    const init = async () => {
      const root = await window.electronAPI.getProjectRoot()
      if (root) {
        setProjectRoot(root)
        await factsStore.setProjectRoot(root)
        // 读取项目名称
        try {
          const result = await window.electronAPI.yaml.read(`${root}/project.yaml`)
          if (result.success && result.data) {
            const data = result.data as Record<string, unknown>
            setProjectName(String(data.title || '小说'))
          }
        } catch {}
      }
    }
    init()
  }, [])


  const handleSave = useCallback(async () => {
    if (!activeChapter || !chapterContent) return

    setSaveStatus('saving')
    try {
      const result = await window.electronAPI.writeFile(activeChapter, chapterContent)
      if (result.success) {
        setIsDirty(false)
        setSaveStatus('saved')
        setTimeout(() => setSaveStatus('idle'), 2000)
      } else {
        setSaveStatus('error')
        message.error(`保存失败：${result.error}`)
        // 保存失败时立即重试一次（捕获当前 chapterContent，避免闭包过期）
        const contentToSave = chapterContent
        setTimeout(async () => {
          setSaveStatus('saving')
          const retry = await window.electronAPI.writeFile(activeChapter, contentToSave)
          if (retry.success) {
            setIsDirty(false)
            setSaveStatus('saved')
            setTimeout(() => setSaveStatus('idle'), 2000)
          } else {
            setSaveStatus('error')
          }
        }, 1000)
      }
    } catch (error) {
      setSaveStatus('error')
      message.error('保存失败')
    }
  }, [activeChapter, chapterContent])

  // 自动保存
  useEffect(() => {
    if (isDirty && activeChapter) {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current)
      autoSaveTimerRef.current = setTimeout(() => {
        handleSave()
      }, 5000)
    }
    return () => {
      if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current)
      autoSaveTimerRef.current = null
    }
  }, [chapterContent, isDirty, activeChapter, handleSave])





  // 打开项目
  const handleOpenProject = () => {
    setProjectManagerVisible(true)
  }

  // 项目打开后的回调
  const handleProjectOpened = async (projectPath: string) => {
    setProjectRoot(projectPath)
    await factsStore.setProjectRoot(projectPath)
    // 同步到 main 进程，否则 main 的路径验证会基于错误的 projectRoot
    await window.electronAPI.setProjectRoot(projectPath)
    // 读取项目名称
    try {
      const result = await window.electronAPI.yaml.read(`${projectPath}/project.yaml`)
      if (result.success && result.data) {
        const data = result.data as Record<string, unknown>
        setProjectName(String(data.title || '小说'))
      }
    } catch {}
  }

  // 章节选择
  const handleChapterSelect = async (filePath: string) => {
    if (isDirty) {
      // 提示保存
      const confirm = window.confirm('当前章节有未保存的内容，是否保存？')
      if (confirm) await handleSave()
    }

    setChapterContent('')
    setActiveChapter(filePath)
    setIsDirty(false)

    // 读取章节内容
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success && result.content) {
        setChapterContent(result.content)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }

  // 内容变化
  const handleContentChange = (value: string | undefined) => {
    if (value === undefined) return
    setChapterContent(value)
    setIsDirty(true)
  }

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [activeChapter, chapterContent])

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 番茄小说创作助手</h2>
          {projectRoot && <span style={{ color: '#999' }}>当前项目：{projectRoot}</span>}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button
            icon={<FolderOpenOutlined />}
            onClick={handleOpenProject}
          >
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={saveStatus === 'saving' || !activeChapter}
            loading={saveStatus === 'saving'}
          >
            {saveStatus === 'saving'
              ? '保存中...'
              : saveStatus === 'saved'
                ? '已保存 ✓'
                : saveStatus === 'error'
                  ? '保存失败 ↺'
                  : isDirty
                    ? '保存 *'
                    : '已保存'}
          </Button>
          <Button
            icon={<BookOutlined />}
            onClick={() => setExportManagerVisible(true)}
            disabled={!projectRoot}
          >
            导出
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧边栏 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={280} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && projectRoot && (
            <OutlineTree
              projectRoot={projectRoot}
              activeChapter={activeChapter}
              onSelect={handleChapterSelect}
            />
          )}
          {activeTab === 'characters' && projectRoot && (
            <CharactersPage
              projectRoot={projectRoot}
              onCharacterClick={(name) => {
                // 可选：切换到大纲并搜索该角色相关内容
              }}
            />
          )}
          {activeTab === 'world' && (
            <SettingsPage projectRoot={projectRoot} />
          )}
          {activeTab === 'facts' && <FactsPanel projectRoot={projectRoot} />}
          {activeTab === 'search' && (
            <VectorSearchPanel
              projectRoot={projectRoot}
              onJumpToChapter={(path) => {
                handleChapterSelect(path)
              }}
            />
          )}
          {activeTab === 'appSettings' && <AppSettingsPage />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff' }}>
          {activeChapter ? (
            <Editor
              ref={editorRef}
              value={chapterContent}
              onChange={handleContentChange}
              filePath={activeChapter}
            />
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
                fontSize: 18,
              }}
            >
              请在左侧选择章节，或打开一个小说项目
            </div>
          )}
        </Content>

        {/* 右侧AI工具区 */}
        <Sider width={320} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', borderBottom: '1px solid #e8e8e8' }}>
            <Button
              type={rightPanelTab === 'ai' ? 'primary' : 'text'}
              size="small"
              style={{ flex: 1, borderRadius: 0 }}
              onClick={() => setRightPanelTab('ai')}
            >
              ✏️ AI工具
            </Button>
            <Button
              type={rightPanelTab === 'analysis' ? 'primary' : 'text'}
              size="small"
              style={{ flex: 1, borderRadius: 0 }}
              onClick={() => setRightPanelTab('analysis')}
            >
              📊 分析
            </Button>
          </div>
          {rightPanelTab === 'ai' ? (
            <AIToolsPanel
              chapterContent={chapterContent}
              chapterPath={activeChapter}
              getSelectedText={() => editorRef.current?.getSelectedText() || ''}
              onInsertText={(text) => {
                if (text.startsWith('__REPLACE__')) {
                  const newContent = text.slice('__REPLACE__'.length)
                  setChapterContent(newContent)
                } else {
                  setChapterContent(prev => prev + text)
                }
                setIsDirty(true)
              }}
            />
          ) : (
            <AnalysisPanel
              chapterContent={chapterContent}
              chapterPath={activeChapter}
              projectRoot={projectRoot}
            />
          )}
        </Sider>
      </Layout>

      {/* 项目管理对话框 */}
      <ProjectManager
        visible={projectManagerVisible}
        onClose={() => setProjectManagerVisible(false)}
        onProjectOpened={handleProjectOpened}
      />
      <ExportManager
        visible={exportManagerVisible}
        projectRoot={projectRoot}
        projectName={projectName}
        onClose={() => setExportManagerVisible(false)}
      />
    </Layout>
  )
}

export default Workbench

/**
 * 事实台账面板
 * 支持按类型/角色/章节筛选，伏笔状态管理，点击跳转章节
 * 新增伏笔看板视图
 */

import { useState, useEffect } from 'react'
import {
  List,
  Tag,
  Tabs,
  Empty,
  Spin,
  Button,
  message,
  Select,
  Input,
  Card,
  Badge,
  Space,
  Tooltip,
  Modal,
  Form,
  InputNumber,
  Switch,
  Alert,
  Row,
  Col,
} from 'antd'
import {
  ThunderboltOutlined,
  FireOutlined,
  GiftOutlined,
  TeamOutlined,
  BulbOutlined,
  ReloadOutlined,
  SearchOutlined,
  FilterOutlined,
  EyeOutlined,
  CheckOutlined,
  ExclamationCircleOutlined,
  DragOutlined,
} from '@ant-design/icons'
import factsStore, { Fact } from '../db'
import factExtractor from '../services/factExtractor'

const { TabPane } = Tabs

type FactType = 'all' | 'power' | 'item' | 'relation' | 'foreshadow'

const typeLabels: Record<FactType, { label: string; icon: React.ReactNode; color: string }> = {
  all: { label: '全部', icon: <ThunderboltOutlined />, color: 'default' },
  power: { label: '战力', icon: <FireOutlined />, color: 'red' },
  item: { label: '物品', icon: <GiftOutlined />, color: 'gold' },
  relation: { label: '关系', icon: <TeamOutlined />, color: 'blue' },
  foreshadow: { label: '伏笔', icon: <BulbOutlined />, color: 'purple' },
}

type ForeshadowStatus = '铺设中' | '待回收' | '已回收'

interface ForeshadowItem {
  id: string
  description: string
  setupChapter: number
  payoffChapter?: number
  status: ForeshadowStatus
  relatedCharacters: string[]
  type: '剧情伏笔' | '人物伏笔' | '世界观伏笔'
  isOverdue?: boolean // 超过10章未回收
}

interface FactsPanelProps {
  projectRoot?: string | null
}

const FactsPanel: React.FC<FactsPanelProps> = ({ projectRoot }) => {
  const [activeTab, setActiveTab] = useState<FactType | 'kanban'>('all')
  const [facts, setFacts] = useState<Fact[]>([])
  const [allFacts, setAllFacts] = useState<Fact[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [filterCharacter, setFilterCharacter] = useState<string>('')
  const [filterChapter, setFilterChapter] = useState<number | undefined>(undefined)
  const [showFilters, setShowFilters] = useState(false)
  const [characters, setCharacters] = useState<string[]>([])
  const [currentChapter, setCurrentChapter] = useState<number>(1)

  // 伏笔看板数据
  const [foreshadowItems, setForeshadowItems] = useState<ForeshadowItem[]>([])
  const [showAddForeshadow, setShowAddForeshadow] = useState(false)
  const [form] = Form.useForm()

  // 加载事实
  const loadFacts = async () => {
    setLoading(true)
    try {
      const result = await factsStore.getFacts(undefined, projectRoot)
      setAllFacts(result)

      // 提取所有角色名
      const charNames = Array.from(
        new Set(result.map(f => f.subject).filter(Boolean))
      ).sort() as string[]
      setCharacters(charNames)

      setAllFacts(result)
      applyFilters(result)

      // 加载伏笔看板（setAllFacts 同步完成，loadForeshadowKanban 读取的是最新 state）
      if (projectRoot) {
        setTimeout(() => loadForeshadowKanban(result), 0)
      }
    } catch (error) {
      message.error('加载事实失败')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  // 加载伏笔看板
  const loadForeshadowKanban = async (facts?: Fact[]) => {
    if (!projectRoot) return
    const allFactsData = facts || allFacts
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        // 获取当前最大章节数（用于判断超期）
        const chapters = allFactsData
          .map((f: Fact) => Math.max(f.chapterStart, f.chapterEnd))
          .filter((c: number) => c < 9999)
        const currentMaxChapter = chapters.length > 0 ? Math.max(...chapters) : currentChapter

        const items: ForeshadowItem[] = foreshadowList.map((fb, idx) => {
          const setupChapter = Number(fb['setup_chapter'] || 1)
          const payoffChapter = fb['payoff_chapter'] ? Number(fb['payoff_chapter']) : undefined
          const status = (fb['status'] as ForeshadowStatus) || '待回收'
          const isOverdue = !!(status !== '已回收' && !payoffChapter && currentMaxChapter >= setupChapter && (currentMaxChapter - setupChapter) > 10)

          return {
            id: String(fb['id'] || `fs-${idx}`),
            description: String(fb['description'] || ''),
            setupChapter,
            payoffChapter,
            status,
            relatedCharacters: (fb['related_characters'] as string[]) || [],
            type: (fb['type'] as ForeshadowItem['type']) || '剧情伏笔',
            isOverdue,
          }
        })

        setForeshadowItems(items)
      }
    } catch (error) {
      console.warn('加载伏笔看板失败:', error)
    }
  }

  // 获取当前最大章节数
  const getCurrentMaxChapter = (): number => {
    // 从 facts 中获取最大的章节号
    const chapters = allFacts
      .map(f => Math.max(f.chapterStart, f.chapterEnd))
      .filter(c => c < 9999)
    return chapters.length > 0 ? Math.max(...chapters) : currentChapter
  }

  // 更新伏笔状态
  const handleUpdateForeshadowStatus = async (
    item: ForeshadowItem,
    newStatus: ForeshadowStatus
  ) => {
    if (!projectRoot) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
        const updated = foreshadowList.map(fb => {
          if (fb['id'] === item.id) {
            return { ...fb, status: newStatus }
          }
          return fb
        })
        plotData['伏笔清单'] = updated
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success(`伏笔状态已更新为「${newStatus}」`)
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('更新失败')
    }
  }

  // 添加伏笔
  const handleAddForeshadow = async () => {
    if (!projectRoot) return
    try {
      const values = await form.validateFields()
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []

        foreshadowList.push({
          id: `FS${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
          description: values.description,
          setup_chapter: values.setupChapter || 1,
          payoff_chapter: values.payoffChapter || undefined,
          status: '铺设中',
          related_characters: values.relatedCharacters || [],
          type: values.type || '剧情伏笔',
        })

        plotData['伏笔清单'] = foreshadowList
        const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
        if (!writeResult.success) {
          message.error(`保存失败: ${writeResult.error}`)
          return
        }
        message.success('伏笔已添加')
        setShowAddForeshadow(false)
        form.resetFields()
        await loadForeshadowKanban()
      }
    } catch (error) {
      message.error('添加失败')
    }
  }

  // 删除伏笔
  const handleDeleteForeshadow = async (item: ForeshadowItem) => {
    if (!projectRoot) return
    Modal.confirm({
      title: '确认删除此伏笔？',
      content: item.description,
      okText: '确认删除',
      okType: 'danger',
      onOk: async () => {
        try {
          const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
          const result = await window.electronAPI.yaml.read(plotFactsFile)
          if (result.success && result.data) {
            const plotData = result.data as Record<string, unknown>
            const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
            const filtered = foreshadowList.filter(fb => fb['id'] !== item.id)
            plotData['伏笔清单'] = filtered
            const writeResult = await window.electronAPI.yaml.write(plotFactsFile, plotData)
            if (!writeResult.success) {
              message.error(`保存失败: ${writeResult.error}`)
              return
            }
            message.success('伏笔已删除')
            await loadForeshadowKanban()
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // 提取当前章节事实
  const extractCurrentChapter = async () => {
    message.info('请在编辑器中选择章节后，使用右侧「AI工具 → 提取事实」功能')
  }

  // 应用筛选
  const applyFilters = (source: Fact[]) => {
    let filtered = source

    if (activeTab !== 'all') {
      filtered = filtered.filter(f => f.type === activeTab)
    }

    if (searchText) {
      const search = searchText.toLowerCase()
      filtered = filtered.filter(
        f =>
          f.subject.toLowerCase().includes(search) ||
          f.object?.toLowerCase().includes(search) ||
          f.content.toLowerCase().includes(search)
      )
    }

    if (filterCharacter) {
      filtered = filtered.filter(
        f => f.subject === filterCharacter || f.object === filterCharacter
      )
    }

    if (filterChapter) {
      filtered = filtered.filter(
        f => f.chapterStart <= filterChapter! && f.chapterEnd >= filterChapter!
      )
    }

    setFacts(filtered)
  }

  // 标签切换时重新筛选
  useEffect(() => {
    if (activeTab !== 'kanban') {
      applyFilters(allFacts)
    }
  }, [activeTab, searchText, filterCharacter, filterChapter])

  // 切换标签时重新加载
  useEffect(() => {
    loadFacts()
  }, [projectRoot])

  // 格式化事实项
  const renderFactItem = (item: Fact) => {
    const typeInfo = typeLabels[item.type as FactType]
    const isForeshadow = item.type === 'foreshadow'

    return (
      <List.Item
        key={item.id}
        style={{ cursor: 'pointer' }}
      >
        <List.Item.Meta
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
              <Tag color={typeInfo.color}>
                {typeInfo.icon} {typeInfo.label}
              </Tag>
              <strong>{item.subject}</strong>
              {item.object && (
                <>
                  <span style={{ color: '#999' }}>→</span>
                  <strong>{item.object}</strong>
                </>
              )}
              {isForeshadow && (
                <Tag
                  color={
                    item.content.includes('已回收')
                      ? 'green'
                      : item.content.includes('铺设中')
                        ? 'blue'
                        : 'orange'
                  }
                  style={{ marginLeft: 4 }}
                >
                  {item.content.includes('已回收') ? '已回收' : item.content.includes('铺设中') ? '铺设中' : '待回收'}
                </Tag>
              )}
            </div>
          }
          description={
            <div>
              <p style={{ margin: '4px 0' }}>{item.content}</p>
              <div
                style={{
                  fontSize: 12,
                  color: '#999',
                  marginTop: 4,
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span>
                  第 {item.chapterStart} 章
                  {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
                </span>
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  // 伏笔看板卡片
  const renderForeshadowCard = (item: ForeshadowItem) => {
    const isOverdue = item.isOverdue

    return (
      <Card
        key={item.id}
        size="small"
        style={{
          marginBottom: 8,
          borderColor: isOverdue ? '#ff4d4f' : undefined,
          borderWidth: isOverdue ? 2 : 1,
        }}
        bodyStyle={{ padding: 10 }}
      >
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div style={{ flex: 1 }}>
            {isOverdue && (
              <Tag color="red" icon={<ExclamationCircleOutlined />} style={{ marginBottom: 4 }}>
                超期未回收
              </Tag>
            )}
            <div style={{ fontSize: 13, marginBottom: 6 }}>{item.description}</div>
            <div style={{ fontSize: 11, color: '#999' }}>
              <span>铺设：第{item.setupChapter}章</span>
              {item.payoffChapter && (
                <span> → 回收：第{item.payoffChapter}章</span>
              )}
            </div>
            {item.relatedCharacters.length > 0 && (
              <div style={{ marginTop: 4 }}>
                {item.relatedCharacters.slice(0, 3).map(char => (
                  <Tag key={char} color="blue" style={{ fontSize: 10 }}>
                    {char}
                  </Tag>
                ))}
                {item.relatedCharacters.length > 3 && (
                  <Tag style={{ fontSize: 10 }}>+{item.relatedCharacters.length - 3}</Tag>
                )}
              </div>
            )}
          </div>
          <Button
            type="text"
            size="small"
            danger
            icon={<CheckOutlined />}
            onClick={(e) => {
              e.stopPropagation()
              handleDeleteForeshadow(item)
            }}
            style={{ marginLeft: 4 }}
          />
        </div>
      </Card>
    )
  }

  // 伏笔看板三列
  const renderForeshadowKanban = () => {
    const columns: { status: ForeshadowStatus; color: string; items: ForeshadowItem[] }[] = [
      { status: '铺设中', color: 'blue', items: foreshadowItems.filter(f => f.status === '铺设中') },
      { status: '待回收', color: 'orange', items: foreshadowItems.filter(f => f.status === '待回收') },
      { status: '已回收', color: 'green', items: foreshadowItems.filter(f => f.status === '已回收') },
    ]

    const overdueCount = foreshadowItems.filter(f => f.isOverdue).length

    return (
      <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '8px 16px', borderBottom: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
            <Space>
              <span style={{ fontWeight: 500 }}>伏笔看板</span>
              <Badge count={foreshadowItems.length} style={{ fontSize: 10 }} />
            </Space>
            <Button
              size="small"
              type="primary"
              icon={<BulbOutlined />}
              onClick={() => setShowAddForeshadow(true)}
            >
              添加伏笔
            </Button>
          </div>
          {overdueCount > 0 && (
            <Alert
              message={`有 ${overdueCount} 个伏笔超过10章未回收（已标红）`}
              type="warning"
              showIcon
              style={{ fontSize: 11, marginBottom: 8 }}
            />
          )}
        </div>

        <div style={{ flex: 1, overflow: 'auto', padding: 12 }}>
          <Row gutter={8}>
            {columns.map(col => (
              <Col key={col.status} span={8}>
                <div
                  style={{
                    background: '#f5f5f5',
                    borderRadius: 8,
                    padding: 8,
                    minHeight: 300,
                  }}
                >
                  <div style={{
                    textAlign: 'center',
                    marginBottom: 8,
                    fontWeight: 500,
                    color: col.color,
                  }}>
                    {col.status}
                    <Badge
                      count={col.items.length}
                      style={{ marginLeft: 6 }}
                      color={col.color}
                    />
                  </div>

                  {col.items.length === 0 ? (
                    <div style={{ textAlign: 'center', color: '#999', padding: 20, fontSize: 12 }}>
                      暂无伏笔
                    </div>
                  ) : (
                    <div>
                      {col.items.map(item => (
                        <div
                          key={item.id}
                          style={{ position: 'relative' }}
                          onClick={() => {
                            if (col.status !== '已回收') {
                              const nextStatus: ForeshadowStatus =
                                col.status === '铺设中' ? '待回收' : '已回收'
                              handleUpdateForeshadowStatus(item, nextStatus)
                            }
                          }}
                        >
                          {renderForeshadowCard(item)}
                          {col.status !== '已回收' && (
                            <div style={{
                              position: 'absolute',
                              bottom: -4,
                              left: '50%',
                              transform: 'translateX(-50%)',
                              fontSize: 10,
                              color: '#999',
                              cursor: 'pointer',
                            }}>
                              ↓ 点击推进
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </Col>
            ))}
          </Row>
        </div>

        {/* 添加伏笔 Modal */}
        <Modal
          title="添加伏笔"
          open={showAddForeshadow}
          onCancel={() => setShowAddForeshadow(false)}
          onOk={handleAddForeshadow}
          okText="添加"
        >
          <Form form={form} layout="vertical">
            <Form.Item
              name="description"
              label="伏笔描述"
              rules={[{ required: true, message: '请输入伏笔描述' }]}
            >
              <Input.TextArea rows={2} placeholder="描述这个伏笔的内容..." />
            </Form.Item>
            <Form.Item name="setupChapter" label="铺设章节" initialValue={1}>
              <InputNumber min={1} style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="payoffChapter" label="计划回收章节">
              <InputNumber min={1} placeholder="留空表示未计划" style={{ width: '100%' }} />
            </Form.Item>
            <Form.Item name="type" label="伏笔类型" initialValue="剧情伏笔">
              <Select
                options={[
                  { value: '剧情伏笔', label: '剧情伏笔' },
                  { value: '人物伏笔', label: '人物伏笔' },
                  { value: '世界观伏笔', label: '世界观伏笔' },
                ]}
              />
            </Form.Item>
            <Form.Item name="relatedCharacters" label="关联角色">
              <Select
                mode="tags"
                placeholder="输入角色名（回车确认）"
                options={characters.map(c => ({ value: c, label: c }))}
              />
            </Form.Item>
          </Form>
        </Modal>
      </div>
    )
  }

  // 统计摘要
  const getSummary = () => {
    const stats = {
      total: allFacts.length,
      power: allFacts.filter(f => f.type === 'power').length,
      item: allFacts.filter(f => f.type === 'item').length,
      relation: allFacts.filter(f => f.type === 'relation').length,
      foreshadow: foreshadowItems.length,
      foreshadowPending: foreshadowItems.filter(f => f.status === '待回收').length,
      foreshadowOverdue: foreshadowItems.filter(f => f.isOverdue).length,
    }
    return stats
  }

  const stats = getSummary()

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
        {/* 统计栏 */}
        <div
          style={{
            display: 'flex',
            gap: 8,
            marginBottom: 10,
            flexWrap: 'wrap',
            fontSize: 12,
          }}
        >
          <Badge count={stats.total} showZero color="#1890ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>全部</span>
          </Badge>
          <Badge count={stats.power} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>战力</span>
          </Badge>
          <Badge count={stats.relation} showZero color="#1677ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>关系</span>
          </Badge>
          <Badge count={stats.foreshadow} showZero color="#722ed1" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>
              伏笔
              {stats.foreshadowPending > 0 && ` (${stats.foreshadowPending}待收)`}
            </span>
          </Badge>
          {stats.foreshadowOverdue > 0 && (
            <Badge count={stats.foreshadowOverdue} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
              <span style={{ padding: '2px 8px', background: '#fff1f0', borderRadius: 4, color: '#ff4d4f' }}>
                超期
              </span>
            </Badge>
          )}
        </div>

        {/* 搜索和筛选 */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 10 }}>
          <Input
            placeholder="搜索事实..."
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            allowClear
            size="small"
            style={{ flex: 1 }}
          />
          <Button
            size="small"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
            type={showFilters ? 'primary' : 'default'}
          >
            筛选
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={loadFacts}
          />
        </div>

        {/* 高级筛选 */}
        {showFilters && (
          <div style={{ marginBottom: 10, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
            <Space direction="vertical" style={{ width: '100%' }}>
              <Select
                placeholder="按角色筛选"
                value={filterCharacter || undefined}
                onChange={(val) => setFilterCharacter(val || '')}
                options={characters.map(c => ({ value: c, label: c }))}
                style={{ width: '100%' }}
                size="small"
                allowClear
                showSearch
              />
              <InputNumber
                placeholder="按章节筛选"
                value={filterChapter}
                onChange={(val) => setFilterChapter(val ?? undefined)}
                min={1}
                style={{ width: '100%' }}
                size="small"
              />
              <Button
                size="small"
                onClick={() => {
                  setFilterCharacter('')
                  setFilterChapter(undefined)
                }}
              >
                清除筛选
              </Button>
            </Space>
          </div>
        )}

        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key as FactType | 'kanban')}
          size="small"
        >
          {Object.entries(typeLabels).map(([key, info]) => (
            <TabPane
              key={key}
              tab={<span>{info.icon} {info.label}</span>}
            />
          ))}
          <TabPane key="kanban" tab={<span><BulbOutlined /> 伏笔看板</span>} />
        </Tabs>
      </div>

      {/* 列表 / 看板 */}
      <div style={{ flex: 1, overflow: 'auto', padding: '0 16px' }}>
        {activeTab === 'kanban' ? (
          renderForeshadowKanban()
        ) : loading ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Spin tip="加载中..." />
          </div>
        ) : facts.length === 0 ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Empty
              description="暂无事实记录"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            />
          </div>
        ) : (
          <List
            dataSource={facts}
            renderItem={renderFactItem}
            size="small"
            style={{ padding: '10px 0' }}
          />
        )}
      </div>
    </div>
  )
}

export default FactsPanel

/**
 * 章节分析面板
 * 提供：自动摘要、人物出场统计、对话分析、情节点提取
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  message,
  Spin,
  Tabs,
  Statistic,
  Row,
  Col,
  Tag,
  List,
  Progress,
  Alert,
  Divider,
} from 'antd'
import {
  FileTextOutlined,
  TeamOutlined,
  MessageOutlined,
  ThunderboltOutlined,
  ReloadOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'

interface AnalysisPanelProps {
  chapterContent: string
  chapterPath: string | null
  projectRoot: string | null
}

interface CharacterAppearance {
  name: string
  count: number
  paragraphs: number
}

interface DialogueInfo {
  speaker: string
  content: string
  position: number
}

interface PlotPoint {
  order: number
  event: string
  description: string
}

const AnalysisPanel: React.FC<AnalysisPanelProps> = ({
  chapterContent,
  chapterPath,
  projectRoot,
}) => {
  const [analyzing, setAnalyzing] = useState(false)
  const [activeTab, setActiveTab] = useState<string>('summary')

  // 摘要
  const [summary, setSummary] = useState('')
  const [summaryLoading, setSummaryLoading] = useState(false)

  // 人物统计
  const [characters, setCharacters] = useState<CharacterAppearance[]>([])
  const [dialogues, setDialogues] = useState<DialogueInfo[]>([])
  const [dialogueRatio, setDialogueRatio] = useState(0)
  const [characterStatsLoading, setCharacterStatsLoading] = useState(false)

  // 情节点
  const [plotPoints, setPlotPoints] = useState<PlotPoint[]>([])
  const [plotPointsLoading, setPlotPointsLoading] = useState(false)

  // 生成自动摘要
  const handleGenerateSummary = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setSummaryLoading(true)
    try {
      const fullPrompt = `请为以下小说章节生成200字左右的摘要，概括核心情节、人物关系变化和关键事件：

${chapterContent.slice(0, 3000)}

摘要（200字左右）：` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是一个小说摘要专家。请用简洁精炼的语言概括章节核心内容。',
      })

      if (result.success && result.content) {
        setSummary(result.content)
        setActiveTab('summary')
      } else {
        message.error(result.error || '摘要生成失败')
      }
    } catch (error) {
      message.error('摘要生成失败')
      console.error('摘要生成失败:', error)
    } finally {
      setSummaryLoading(false)
    }
  }

  // 人物出场统计
  const handleCharacterStats = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }
    setCharacterStatsLoading(true)
    try {
      // 读取角色列表
      let characterNames: string[] = []
      const charactersDir = `${projectRoot}/characters`
      const charsExistsResult = await window.electronAPI.exists(charactersDir)
      if (!charsExistsResult.success || !charsExistsResult.exists) {
        setCharacters([])
        setCharacterStatsLoading(false)
        return
      }
      const entriesResult = await window.electronAPI.readdir(charactersDir)
      if (!entriesResult.success) { console.error('读取characters目录失败:', entriesResult.error); setCharacters([]); setCharacterStatsLoading(false); return; }
      const entries = entriesResult.data || []
      const yamlFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )
      for (const file of yamlFiles) {
        const result = await window.electronAPI.yaml.read(`${charactersDir}/${file.name}`)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          if (data.name && typeof data.name === 'string') {
            characterNames.push(data.name)
          }
        }
      }

      // 统计章节中出现的人物
      const content = chapterContent
      const charAppearances: Record<string, { count: number; paragraphs: Set<number> }> = {}

      // 按段落分割
      const paragraphs = content.split(/\n\n+/)

      paragraphs.forEach((para, paraIdx) => {
        for (const name of characterNames) {
          if (para.includes(name)) {
            if (!charAppearances[name]) {
              charAppearances[name] = { count: 0, paragraphs: new Set() }
            }
            charAppearances[name].count++
            charAppearances[name].paragraphs.add(paraIdx)
          }
        }
      })

      const sortedChars = Object.entries(charAppearances)
        .map(([name, stats]) => ({
          name,
          count: stats.count,
          paragraphs: stats.paragraphs.size,
        }))
        .sort((a, b) => b.count - a.count)

      setCharacters(sortedChars)

      // 提取对话
      const dialogueRegex = /[""''『』]([^""''『』]+)[""''『』]/g
      const extractedDialogues: DialogueInfo[] = []
      let match
      let pos = 0
      while ((match = dialogueRegex.exec(content)) !== null) {
        extractedDialogues.push({
          speaker: '',
          content: match[1],
          position: match.index,
        })
        pos++
        if (pos > 50) break
      }

      // 尝试识别说话者（简化版：找引号前的名字）
      const speakerRegex = /([A-Za-z\u4e00-\u9fa5]{2,4})[""'']/
      for (const d of extractedDialogues) {
        const beforeContent = content.slice(Math.max(0, d.position - 30), d.position)
        const speakerMatch = beforeContent.match(speakerRegex)
        if (speakerMatch) {
          d.speaker = speakerMatch[1]
        }
      }

      setDialogues(extractedDialogues.slice(0, 20))

      // 计算对话占比
      const totalChars = content.replace(/\s/g, '').length
      const dialogueChars = extractedDialogues.reduce((sum, d) => sum + d.content.length, 0)
      setDialogueRatio(totalChars > 0 ? (dialogueChars / totalChars) * 100 : 0)

      setActiveTab('characters')
    } catch (error) {
      message.error('统计分析失败')
    } finally {
      setCharacterStatsLoading(false)
    }
  }

  // 情节点提取
  const handlePlotPoints = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setPlotPointsLoading(true)
    try {
      const fullPrompt = `请分析以下小说章节，提取3-5个关键情节点，按时间顺序列出：

${chapterContent.slice(0, 3000)}

情节点列表（格式）：
1. [事件名称] - 简要描述
2. [事件名称] - 简要描述
...` as string

      const result = await aiModelService.call('summary', fullPrompt, {
        systemPrompt: '你是小说情节分析专家。请按时间顺序列出章节的关键事件。',
      })

      if (result.success && result.content) {
        // 解析情节点
        const lines = result.content.split('\n').filter(l => l.trim())
        const points: PlotPoint[] = []
        let order = 1
        for (const line of lines) {
          const match = line.match(/^\d+[.、]\s*(\[.+?\])?\s*(.+)/)
          if (match) {
            points.push({
              order: order++,
              event: match[1] || `情节点${order - 1}`,
              description: match[2].trim(),
            })
          }
        }
        if (points.length === 0) {
          points.push({ order: 1, event: '主要情节点', description: result.content })
        }
        setPlotPoints(points)
        setActiveTab('plotpoints')
      } else {
        message.error(result.error || '情节点提取失败')
      }
    } catch (error) {
      message.error('情节点提取失败')
    } finally {
      setPlotPointsLoading(false)
    }
  }

  // 快速分析（一次性生成所有）
  const handleFullAnalysis = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setAnalyzing(true)
    try {
      await handleGenerateSummary()
      await handleCharacterStats()
      await handlePlotPoints()
    } catch (error) {
      console.error('全量分析失败:', error)
    } finally {
      setAnalyzing(false)
    }
  }

  if (!chapterContent) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先选择章节
      </div>
    )
  }

  const totalChars = chapterContent.replace(/\s/g, '').length
  const wordCount = chapterContent.length

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>📊 章节分析</span>
        </div>

        {/* 基础统计 */}
        <Row gutter={8} style={{ marginBottom: 10 }}>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字数</span>}
              value={wordCount}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>字符</span>}
              value={totalChars}
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
          <Col span={8}>
            <Statistic
              title={<span style={{ fontSize: 11 }}>对话占比</span>}
              value={dialogueRatio.toFixed(1)}
              suffix="%"
              valueStyle={{ fontSize: 16 }}
            />
          </Col>
        </Row>

        {/* 分析按钮 */}
        <Space wrap style={{ marginBottom: 8 }}>
          <Button
            size="small"
            icon={<FileTextOutlined />}
            onClick={handleGenerateSummary}
            loading={summaryLoading}
          >
            生成摘要
          </Button>
          <Button
            size="small"
            icon={<TeamOutlined />}
            onClick={handleCharacterStats}
            loading={characterStatsLoading}
          >
            人物统计
          </Button>
          <Button
            size="small"
            icon={<ThunderboltOutlined />}
            onClick={handlePlotPoints}
            loading={plotPointsLoading}
          >
            情节点
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleFullAnalysis}
            loading={analyzing}
          >
            全部分析
          </Button>
        </Space>
      </div>

      {/* 分析结果 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          size="small"
          items={[
            {
              key: 'summary',
              label: <span>📝 摘要</span>,
              children: (
                <div>
                  {summaryLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="生成摘要中..." />
                    </div>
                  ) : summary ? (
                    <Card size="small" style={{ whiteSpace: 'pre-wrap' }}>
                      {summary}
                    </Card>
                  ) : (
                    <Alert
                      message="点击「生成摘要」获取本章200字摘要"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'characters',
              label: <span>👥 人物</span>,
              children: (
                <div>
                  {characterStatsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="分析人物中..." />
                    </div>
                  ) : (
                    <>
                      {/* 人物出场 */}
                      {characters.length > 0 ? (
                        <Card
                          size="small"
                          title="人物出场统计"
                          style={{ marginBottom: 12 }}
                        >
                          <List
                            size="small"
                            dataSource={characters.slice(0, 10)}
                            renderItem={(char) => (
                              <List.Item>
                                <div style={{ display: 'flex', justifyContent: 'space-between', width: '100%', alignItems: 'center' }}>
                                  <Tag color="blue">{char.name}</Tag>
                                  <Space size="small">
                                    <span style={{ fontSize: 11, color: '#999' }}>
                                      提及 {char.count} 次 · {char.paragraphs} 段
                                    </span>
                                    <Progress
                                      percent={Math.round((char.count / characters[0].count) * 100)}
                                      size="small"
                                      style={{ width: 60 }}
                                    />
                                  </Space>
                                </div>
                              </List.Item>
                            )}
                          />
                        </Card>
                      ) : (
                        <Alert
                          message="点击「人物统计」分析本章出场人物"
                          type="info"
                          showIcon
                        />
                      )}

                      {/* 对话分析 */}
                      {dialogues.length > 0 && (
                        <Card size="small" title="对话片段">
                          <List
                            size="small"
                            dataSource={dialogues.slice(0, 8)}
                            renderItem={(d) => (
                              <List.Item>
                                <div style={{ width: '100%' }}>
                                  {d.speaker && <Tag color="green" style={{ marginBottom: 4 }}>{d.speaker}</Tag>}
                                  <div style={{ fontSize: 12, fontStyle: 'italic', color: '#666' }}>
                                    「{d.content.slice(0, 60)}{d.content.length > 60 ? '...' : ''}」
                                  </div>
                                </div>
                              </List.Item>
                            )}
                          />
                          <Divider style={{ margin: '8px 0' }} />
                          <div style={{ fontSize: 11, color: '#999' }}>
                            共 {dialogues.length} 段对话，对话占比 {dialogueRatio.toFixed(1)}%
                          </div>
                        </Card>
                      )}
                    </>
                  )}
                </div>
              ),
            },
            {
              key: 'plotpoints',
              label: <span>⚡ 情节点</span>,
              children: (
                <div>
                  {plotPointsLoading ? (
                    <div style={{ textAlign: 'center', padding: 40 }}>
                      <Spin tip="提取情节点中..." />
                    </div>
                  ) : plotPoints.length > 0 ? (
                    <Card size="small" title="本章关键情节点">
                      <List
                        size="small"
                        dataSource={plotPoints}
                        renderItem={(point) => (
                          <List.Item>
                            <List.Item.Meta
                              avatar={<div style={{
                                width: 24,
                                height: 24,
                                borderRadius: '50%',
                                background: '#1890ff',
                                color: '#fff',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                fontSize: 12,
                              }}>
                                {point.order}
                              </div>}
                              title={<span>{point.event}</span>}
                              description={<span style={{ fontSize: 12, color: '#666' }}>{point.description}</span>}
                            />
                          </List.Item>
                        )}
                      />
                    </Card>
                  ) : (
                    <Alert
                      message="点击「情节点」提取本章关键事件"
                      type="info"
                      showIcon
                    />
                  )}
                </div>
              ),
            },
          ]}
        />
      </div>
    </div>
  )
}

export default AnalysisPanel

import { useEffect, useRef, useState, forwardRef, useImperativeHandle } from 'react'
import * as monaco from 'monaco-editor'
import { Spin } from 'antd'
import { loader } from '@monaco-editor/react'

// 配置 Monaco Editor 加载路径
loader.config({
  paths: {
    vs: 'https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs'
  }
})

export interface EditorHandle {
  getSelectedText: () => string
  getCursorPosition: () => { lineNumber: number; column: number }
  insertText: (text: string) => void
  replaceSelection: (text: string) => void
}

interface EditorProps {
  value: string
  onChange: (value: string | undefined) => void
  filePath?: string
}

const Editor = forwardRef<EditorHandle, EditorProps>(({ value, onChange, filePath }, ref) => {
  const editorRef = useRef<HTMLDivElement>(null)
  const monacoEditorRef = useRef<monaco.editor.IStandaloneCodeEditor | null>(null)
  const [loading, setLoading] = useState(true)

  // 暴露编辑器方法给父组件
  useImperativeHandle(ref, () => ({
    getSelectedText: () => {
      if (!monacoEditorRef.current) return ''
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return ''
      return monacoEditorRef.current.getModel()?.getValueInRange(selection) || ''
    },
    getCursorPosition: () => {
      if (!monacoEditorRef.current) return { lineNumber: 1, column: 1 }
      const pos = monacoEditorRef.current.getPosition()
      return pos || { lineNumber: 1, column: 1 }
    },
    insertText: (text: string) => {
      if (!monacoEditorRef.current) return
      const position = monacoEditorRef.current.getPosition()
      if (position) {
        const range = new monaco.Range(
          position.lineNumber,
          position.column,
          position.lineNumber,
          position.column
        )
        monacoEditorRef.current.executeEdits('', [
          { range, text }
        ])
      }
    },
    replaceSelection: (text: string) => {
      if (!monacoEditorRef.current) return
      const selection = monacoEditorRef.current.getSelection()
      if (!selection) return
      monacoEditorRef.current.executeEdits('', [
        { range: selection, text }
      ])
    },
  }))

  // 初始化编辑器
  useEffect(() => {
    if (!editorRef.current) return

    let isMounted = true

    const initEditor = async () => {
      try {
        // 加载 Monaco Editor
        await loader.init()

        if (!isMounted || !editorRef.current) return

        // 创建编辑器实例
        const editor = monaco.editor.create(editorRef.current, {
          value,
          language: 'markdown',
          theme: 'vs-light',
          fontSize: 16,
          lineHeight: 1.8,
          lineNumbers: 'on',
          wordWrap: 'on',
          wrappingIndent: 'indent',
          automaticLayout: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
          tabSize: 2,
          insertSpaces: true,
          renderWhitespace: 'none',
          renderLineHighlight: 'line',
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
          },
        })

        // 监听内容变化（带防抖，避免每次按键都触发父组件重渲染）
        let debounceTimer: ReturnType<typeof setTimeout> | null = null
        editor.onDidChangeModelContent(() => {
          if (debounceTimer) clearTimeout(debounceTimer)
          debounceTimer = setTimeout(() => {
            const newValue = editor.getValue()
            onChange(newValue)
          }, 300)
        })

        // 保存快捷键
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
          // 保存由 Workbench 处理
          const saveEvent = new KeyboardEvent('keydown', {
            key: 's',
            ctrlKey: true,
            bubbles: true
          })
          window.dispatchEvent(saveEvent)
        })

        monacoEditorRef.current = editor
        setLoading(false)
      } catch (error) {
        console.error('初始化编辑器失败:', error)
        setLoading(false)
      }
    }

    initEditor()

    return () => {
      isMounted = false
      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])

  // 当外部 value 变化时更新编辑器内容
  useEffect(() => {
    if (!monacoEditorRef.current) return

    const currentValue = monacoEditorRef.current.getValue()
    if (currentValue !== value) {
      // 使用 executeEdits 替代 setValue，保留 undo/redo 历史
      const model = monacoEditorRef.current.getModel()
      if (model) {
        monacoEditorRef.current.executeEdits('', [{
          range: model.getFullModelRange(),
          text: value,
        }])
      }
    }
  }, [value])

  // 根据文件类型切换语言模式
  useEffect(() => {
    if (!monacoEditorRef.current || !filePath) return

    const model = monacoEditorRef.current.getModel()
    if (!model) return

    if (filePath.endsWith('.md') || filePath.endsWith('.markdown')) {
      monaco.editor.setModelLanguage(model, 'markdown')
    } else if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
      monaco.editor.setModelLanguage(model, 'yaml')
    } else if (filePath.endsWith('.json')) {
      monaco.editor.setModelLanguage(model, 'json')
    }
  }, [filePath])

  if (loading) {
    return (
      <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin tip="加载编辑器中..." />
      </div>
    )
  }

  return (
    <div ref={editorRef} style={{ width: '100%', height: '100%' }} />
  )
})

export default Editor

/**
 * 向量语义检索面板
 * 提供相似章节搜索功能
 *
 * 降级方案：基于倒排索引的关键词搜索
 * 当 @xenova/transformers 不可用时自动启用
 */

import { useState, useEffect, useMemo, useRef } from 'react'
import {
  Input,
  Button,
  List,
  Card,
  Tag,
  Space,
  message,
  Alert,
  Spin,
  Modal,
  Select,
  Tooltip,
  Checkbox,
  Badge,
} from 'antd'
import {
  SearchOutlined,
  BuildOutlined,
  CheckCircleOutlined,
  WarningOutlined,
  ReloadOutlined,
  FilterOutlined,
} from '@ant-design/icons'

interface SearchResult {
  chapterPath: string
  chapterName: string
  score: number
  snippet: string
  matchedWords: string[]
}

interface ChapterEntry {
  path: string
  name: string
  content: string
}

interface InvertedIndex {
  vocabulary: Map<string, Set<string>> // word -> Set<chapterPath>
  totalDocs: number
  docLengths: Map<string, number>
}

interface VectorSearchPanelProps {
  projectRoot: string | null
  onJumpToChapter?: (chapterPath: string) => void
}

const VectorSearchPanel: React.FC<VectorSearchPanelProps> = ({
  projectRoot,
  onJumpToChapter,
}) => {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [loading, setLoading] = useState(false)
  const [indexLoading, setIndexLoading] = useState(false)
  const [chapters, setChapters] = useState<ChapterEntry[]>([])
  const [invertedIndex, setInvertedIndex] = useState<InvertedIndex | null>(null)
  const [queryMode, setQueryMode] = useState<'AND' | 'OR'>('AND')
  const [chapterRange, setChapterRange] = useState<{ start?: number; end?: number }>({})
  const [showFilters, setShowFilters] = useState(false)
  const [indexStats, setIndexStats] = useState<{ wordCount: number; chapterCount: number } | null>(null)
  const loadIdRef = useRef(0)

  // 加载所有章节内容并构建倒排索引
  const loadChaptersAndBuildIndex = async (loadId: number): Promise<{ chapters: ChapterEntry[]; index: InvertedIndex } | null> => {
    if (!projectRoot) return null
    if (loadIdRef.current !== loadId) return null  // 忽略过时调用

    setIndexLoading(true)
    const loadedChapters: ChapterEntry[] = []

    const readDir = async (dirPath: string) => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              loadedChapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    let dirExists = false
    try {
      const r = await window.electronAPI.exists(plotsDir)
      dirExists = !!(r && r.success && r.exists)
    } catch (e) {
      console.warn('exists 调用异常:', e)
    }
    if (dirExists) {
      await readDir(plotsDir)
    }

    if (loadedChapters.length === 0) {
      setIndexLoading(false)
      return null
    }

    if (loadIdRef.current !== loadId) return null  // 忽略过时调用
    setChapters(loadedChapters)

    // 构建倒排索引
    const vocab = new Map<string, Set<string>>()
    const docLengths = new Map<string, number>()

    // 中文分词简单实现（基于字典+规则）
    const tokenize = (text: string): string[] => {
      // 去除标点和空格，转小写
      const clean = text.replace(/[^\w\u4e00-\u9fa5]/g, ' ').toLowerCase()
      // 简单按空格和非汉字字符分割
      const words = clean.split(/[\s,。！？、：；""''【】『』]+/).filter(w => w.length >= 1)
      return words
    }

    for (const ch of loadedChapters) {
      const words = tokenize(ch.content)
      docLengths.set(ch.path, words.length)

      for (const word of words) {
        if (word.length < 1) continue
        if (!vocab.has(word)) {
          vocab.set(word, new Set())
        }
        vocab.get(word)!.add(ch.path)
      }
    }

    const index: InvertedIndex = {
      vocabulary: vocab,
      totalDocs: loadedChapters.length,
      docLengths,
    }

    if (loadIdRef.current !== loadId) return null  // 忽略过时调用
    setInvertedIndex(index)
    setIndexStats({
      wordCount: vocab.size,
      chapterCount: loadedChapters.length,
    })
    setIndexLoading(false)

    return { chapters: loadedChapters, index }
  }

  // 初始化时构建索引
  useEffect(() => {
    if (projectRoot) {
      loadIdRef.current += 1
      loadChaptersAndBuildIndex(loadIdRef.current)
    }
  }, [projectRoot])

  // 搜索
  const performSearch = async () => {
    if (!query.trim()) {
      message.warning('请输入搜索内容')
      return
    }
    if (!invertedIndex || chapters.length === 0) {
      message.warning('正在加载索引，请稍候...')
      await loadChaptersAndBuildIndex(loadIdRef.current)
      if (!invertedIndex) return
    }

    setLoading(true)
    setResults([])

    try {
      // 分词
      const queryWords = query
        .toLowerCase()
        .replace(/[^\w\u4e00-\u9fa5]/g, ' ')
        .split(/\s+/)
        .filter(w => w.length >= 1)

      if (queryWords.length === 0) {
        setLoading(false)
        return
      }

      // 找出包含查询词的文档
      const docScores = new Map<string, { score: number; matchedWords: Set<string> }>()

      for (const word of queryWords) {
        const docSet = invertedIndex.vocabulary.get(word)
        if (!docSet) continue

        // IDF 权重（简化版）
        const docFreq = docSet.size
        const idf = Math.log((invertedIndex.totalDocs + 1) / (docFreq + 1))

        for (const docPath of docSet) {
          const docLen = invertedIndex.docLengths.get(docPath) || 1
          const tf = 1 // 简化：每个词出现一次

          if (!docScores.has(docPath)) {
            docScores.set(docPath, { score: 0, matchedWords: new Set() })
          }
          const entry = docScores.get(docPath)!
          entry.score += (tf / docLen) * idf
          entry.matchedWords.add(word)
        }
      }

      // 过滤：AND 模式要求所有词都匹配
      let filteredDocs = Array.from(docScores.entries())

      if (queryMode === 'AND') {
        filteredDocs = filteredDocs.filter(([, entry]) =>
          queryWords.every(w => entry.matchedWords.has(w))
        )
      }

      // 章节范围过滤
      if (chapterRange.start || chapterRange.end) {
        filteredDocs = filteredDocs.filter(([path]) => {
          const ch = chapters.find(c => c.path === path)
          if (!ch) return true
          const match = ch.name.match(/第(\d+)章/)
          if (!match) return true
          const chNum = parseInt(match[1])
          if (chapterRange.start && chNum < chapterRange.start) return false
          if (chapterRange.end && chNum > chapterRange.end) return false
          return true
        })
      }

      // 排序并生成结果
      const searchResults: SearchResult[] = filteredDocs
        .sort((a, b) => b[1].score - a[1].score)
        .slice(0, 10)
        .map(([path, entry]) => {
          const ch = chapters.find(c => c.path === path)
          // 生成片段
          let snippet = ''
          if (ch) {
            const contentLower = ch.content.toLowerCase()
            const firstMatchIdx = Math.min(...queryWords.map(w => contentLower.indexOf(w)).filter(i => i >= 0))
            if (firstMatchIdx >= 0) {
              const start = Math.max(0, firstMatchIdx - 40)
              const end = Math.min(ch.content.length, firstMatchIdx + 100)
              snippet = (start > 0 ? '...' : '') + ch.content.slice(start, end) + (end < ch.content.length ? '...' : '')
            } else {
              snippet = ch.content.slice(0, 120) + '...'
            }
          }

          return {
            chapterPath: path,
            chapterName: ch?.name || path,
            score: entry.score,
            snippet,
            matchedWords: Array.from(entry.matchedWords),
          }
        })

      setResults(searchResults)

      if (searchResults.length === 0) {
        message.info('未找到匹配章节，尝试使用 OR 模式或放宽筛选条件')
      }
    } catch (error) {
      console.error('搜索失败:', error)
      message.error('搜索失败')
    } finally {
      setLoading(false)
    }
  }

  // 重建索引
  const handleRebuildIndex = async () => {
    setInvertedIndex(null)
    setResults([])
    await loadChaptersAndBuildIndex(loadIdRef.current)
    message.success('索引已重建')
  }

  // 高亮匹配的词
  const highlightMatches = (text: string, words: string[]): React.ReactNode => {
    if (!words.length) return text

    let result = text
    const parts: { text: string; highlight: boolean }[] = []

    // 简单高亮实现
    const lowerText = text.toLowerCase()
    const allMatches: { start: number; end: number }[] = []

    for (const word of words) {
      let idx = lowerText.indexOf(word.toLowerCase())
      while (idx >= 0) {
        allMatches.push({ start: idx, end: idx + word.length })
        idx = lowerText.indexOf(word.toLowerCase(), idx + 1)
      }
    }

    if (allMatches.length === 0) return text

    // 合并重叠区间并排序
    allMatches.sort((a, b) => a.start - b.start)
    const merged: { start: number; end: number }[] = []
    for (const m of allMatches) {
      if (merged.length === 0 || merged[merged.length - 1].end < m.start) {
        merged.push(m)
      } else {
        merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, m.end)
      }
    }

    let lastEnd = 0
    for (const m of merged) {
      if (m.start > lastEnd) {
        parts.push({ text: result.slice(lastEnd, m.start), highlight: false })
      }
      parts.push({ text: result.slice(m.start, m.end), highlight: true })
      lastEnd = m.end
    }
    if (lastEnd < result.length) {
      parts.push({ text: result.slice(lastEnd), highlight: false })
    }

    return (
      <>
        {parts.map((p, i) =>
          p.highlight ? (
            <mark key={i} style={{ background: '#ffe58f', padding: '0 2px' }}>{p.text}</mark>
          ) : (
            <span key={i}>{p.text}</span>
          )
        )}
      </>
    )
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <Space>
            <span style={{ fontSize: 13, fontWeight: 500 }}>🔍 相似章节检索</span>
            {indexStats && (
              <Tag color="green">
                索引: {indexStats.wordCount} 词 / {indexStats.chapterCount} 章
              </Tag>
            )}
          </Space>
        </div>

        {/* 索引状态 */}
        <div style={{ marginBottom: 10, fontSize: 12 }}>
          {indexLoading ? (
            <Tag icon={<Spin size="small" />}>正在构建索引...</Tag>
          ) : invertedIndex ? (
            <Tag color="green" icon={<CheckCircleOutlined />}>
              倒排索引已就绪
            </Tag>
          ) : (
            <Tag color="orange" icon={<WarningOutlined />}>
              索引未构建
            </Tag>
          )}
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={handleRebuildIndex}
            style={{ marginLeft: 8 }}
          >
            重建索引
          </Button>
        </div>

        {/* 搜索框 */}
        <Space direction="vertical" style={{ width: '100%' }}>
          <Input.Search
            placeholder="输入情节描述、角色名或关键词..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onSearch={performSearch}
            loading={loading}
            enterButton={
              <Button type="primary" icon={<SearchOutlined />}>
                搜索
              </Button>
            }
          />
        </Space>

        {/* 搜索选项 */}
        <div style={{ marginTop: 8 }}>
          <Button
            size="small"
            type="text"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
          >
            高级选项 {showFilters ? '▲' : '▼'}
          </Button>
          {showFilters && (
            <div style={{ marginTop: 8, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
              <Space direction="vertical" style={{ width: '100%' }}>
                <div>
                  <span style={{ fontSize: 11, marginRight: 8 }}>匹配模式：</span>
                  <Select
                    size="small"
                    value={queryMode}
                    onChange={setQueryMode}
                    options={[
                      { value: 'AND', label: 'AND（所有词都匹配）' },
                      { value: 'OR', label: 'OR（任一词匹配）' },
                    ]}
                    style={{ width: 160 }}
                  />
                </div>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                  <span style={{ fontSize: 11 }}>章节范围：</span>
                  <Input
                    size="small"
                    placeholder="起始章"
                    type="number"
                    min={1}
                    style={{ width: 70 }}
                    value={chapterRange.start || ''}
                    onChange={(e) => setChapterRange(prev => ({
                      ...prev,
                      start: e.target.value ? parseInt(e.target.value) : undefined
                    }))}
                  />
                  <span>-</span>
                  <Input
                    size="small"
                    placeholder="结束章"
                    type="number"
                    min={1}
                    style={{ width: 70 }}
                    value={chapterRange.end || ''}
                    onChange={(e) => setChapterRange(prev => ({
                      ...prev,
                      end: e.target.value ? parseInt(e.target.value) : undefined
                    }))}
                  />
                </div>
              </Space>
            </div>
          )}
        </div>

        <Alert
          message="使用倒排索引进行关键词检索，支持 AND/OR 查询和章节范围过滤"
          type="info"
          showIcon
          style={{ marginTop: 8, fontSize: 11 }}
        />
      </div>

      {/* 结果列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading || indexLoading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip={indexLoading ? '构建索引中...' : '搜索中...'} />
          </div>
        ) : results.length === 0 ? (
          <div style={{ color: '#999', textAlign: 'center', padding: 40, fontSize: 13 }}>
            {query ? '未找到相似章节' : '输入内容开始搜索'}
          </div>
        ) : (
          <List
            dataSource={results}
            renderItem={(item) => (
              <List.Item
                style={{ cursor: 'pointer' }}
                onClick={() => onJumpToChapter?.(item.chapterPath)}
              >
                <List.Item.Meta
                  title={
                    <Space>
                      <span>{item.chapterName}</span>
                      <Tag color="blue">
                        匹配度 {Math.round(item.score * 100)}%
                      </Tag>
                      {item.matchedWords.slice(0, 3).map(w => (
                        <Tag key={w} color="purple" style={{ fontSize: 10 }}>
                          {w}
                        </Tag>
                      ))}
                    </Space>
                  }
                  description={
                    <div
                      style={{
                        fontSize: 12,
                        color: '#666',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        display: '-webkit-box',
                        WebkitLineClamp: 2,
                        WebkitBoxOrient: 'vertical',
                      }}
                    >
                      {highlightMatches(item.snippet, item.matchedWords)}
                    </div>
                  }
                />
              </List.Item>
            )}
          />
        )}
      </div>
    </div>
  )
}

export default VectorSearchPanel

