      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])  // ← onChange 缺失

修复建议：改用 ref 保存 onChange（const onChangeRef = useRef(onChange); onChangeRef.current = onChange）以确保始终调用最新版本，或将 onChange 加入依赖数组。
